```{.r .cell-code}
library(dplyr)
library(tidyr)
library(ggplot2)

claims_long <- dataset %>%
  select(
    year,
    liability_claims,
    liability_property_claims,
    liability_injury_claims,
    property_claims,
    theft_claims,
    fire_claims,
    glass_claims,
    legal_protection_claims,
    occupants_claims
  ) %>%
  pivot_longer(
    cols = -year,
    names_to = "claim_type",
    values_to = "claims"
  ) %>%
  group_by(year, claim_type) %>%
  summarise(
    total_claims_year = sum(claims, na.rm = TRUE),
    .groups = "drop"
  )

ggplot(claims_long,
       aes(x = year,
           y = total_claims_year,
