  geom_line(
    colour = "purple",
    linewidth = 1
  ) +

  geom_point(
    colour = "purple",
    size = 2.5
  ) +

  facet_wrap(
    ~ claim_type,
    scales = "free_y"
  ) +

  labs(
    title = "Trend of Claims Over Time by Claim Type",
    x = "Year",
    y = "Total Claims"
  ) +

  theme_minimal()
```
